SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;


-- 1. Tabel Referensi Hewan
DROP TABLE IF EXISTS `ref_hewan`;
CREATE TABLE `ref_hewan` (
  `id_hewan` VARCHAR(10) NOT NULL,
  `nama_hewan` VARCHAR(50) NOT NULL,
  `kategori` VARCHAR(50) NOT NULL,
  PRIMARY KEY (`id_hewan`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- 2. Tabel Referensi Wilayah
DROP TABLE IF EXISTS `ref_wilayah`;
CREATE TABLE `ref_wilayah` (
  `id_wilayah` INT NOT NULL AUTO_INCREMENT,
  `provinsi` VARCHAR(100) NOT NULL,
  PRIMARY KEY (`id_wilayah`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- 3. Tabel Transaksi Mutasi
DROP TABLE IF EXISTS `tr_mutasi`;
CREATE TABLE `tr_mutasi` (
  `id_mutasi` VARCHAR(15) NOT NULL,
  `tgl_mutasi` VARCHAR(10) DEFAULT NULL,
  `id_asal` INT DEFAULT NULL,
  `id_tujuan` INT DEFAULT NULL,
  `id_hewan` VARCHAR(10) DEFAULT NULL,
  `jumlah_ekor` INT DEFAULT NULL, 
  PRIMARY KEY (`id_mutasi`),
  CONSTRAINT `fk_mutasi_asal` FOREIGN KEY (`id_asal`) REFERENCES `ref_wilayah` (`id_wilayah`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_mutasi_tujuan` FOREIGN KEY (`id_tujuan`) REFERENCES `ref_wilayah` (`id_wilayah`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_mutasi_hewan` FOREIGN KEY (`id_hewan`) REFERENCES `ref_hewan` (`id_hewan`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- 4. Tabel Transaksi Laporan Sakit
DROP TABLE IF EXISTS `tr_laporan_sakit`;
CREATE TABLE `tr_laporan_sakit` (
  `id_laporan` VARCHAR(15) NOT NULL,
  `tgl_lapor` VARCHAR(10) DEFAULT NULL,
  `id_wilayah` INT DEFAULT NULL,
  `id_hewan` VARCHAR(10) DEFAULT NULL,
  `jumlah_gejala` INT DEFAULT NULL,
  PRIMARY KEY (`id_laporan`),
  CONSTRAINT `fk_sakit_wilayah` FOREIGN KEY (`id_wilayah`) REFERENCES `ref_wilayah` (`id_wilayah`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_sakit_hewan` FOREIGN KEY (`id_hewan`) REFERENCES `ref_hewan` (`id_hewan`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;



-- 5. Tabel Transaksi Hasil Lab
DROP TABLE IF EXISTS `tr_hasil_lab`;
CREATE TABLE `tr_hasil_lab` (
  `id_uji` VARCHAR(15) NOT NULL,
  `id_laporan` VARCHAR(15) DEFAULT NULL,
  `tgl_uji` VARCHAR(10) DEFAULT NULL,
  `penyakit` VARCHAR(100) DEFAULT NULL,
  `hasil_uji` ENUM('Positif', 'Negatif') DEFAULT NULL,
  PRIMARY KEY (`id_uji`),
  CONSTRAINT `fk_lab_laporan` FOREIGN KEY (`id_laporan`) REFERENCES `tr_laporan_sakit` (`id_laporan`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- 6. Tabel Transaksi RPH (Rumah Potong Hewan)
DROP TABLE IF EXISTS `tr_rph`;
CREATE TABLE `tr_rph` (
  `id_potong` VARCHAR(15) NOT NULL,
  `tgl_potong` VARCHAR(10) DEFAULT NULL,
  `id_wilayah` INT DEFAULT NULL,
  `id_hewan` VARCHAR(10) DEFAULT NULL,
  `berat_karkas` DOUBLE DEFAULT NULL,
  PRIMARY KEY (`id_potong`),
  CONSTRAINT `fk_rph_wilayah` FOREIGN KEY (`id_wilayah`) REFERENCES `ref_wilayah` (`id_wilayah`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_rph_hewan` FOREIGN KEY (`id_hewan`) REFERENCES `ref_hewan` (`id_hewan`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


SET FOREIGN_KEY_CHECKS = 1;
